class Solution:
    def maxTargetNodes(self, edges1, edges2):
        # independent re-derivation: explicit breadth-first search per node,
        # counting even-length paths directly instead of using tree coloring
        from collections import deque
        n = len(edges1) + 1
        m = len(edges2) + 1
        adj1 = [[] for _ in range(n)]
        for a, b in edges1:
            adj1[a].append(b); adj1[b].append(a)
        adj2 = [[] for _ in range(m)]
        for a, b in edges2:
            adj2[a].append(b); adj2[b].append(a)
        def even_count(adj, src):
            dist = {src: 0}
            q = deque([src])
            cnt = 0
            while q:
                u = q.popleft()
                if dist[u] % 2 == 0:
                    cnt += 1
                for v in adj[u]:
                    if v not in dist:
                        dist[v] = dist[u] + 1
                        q.append(v)
            return cnt
        def odd_count(adj, src, size):
            return size - even_count(adj, src)
        best2 = max(odd_count(adj2, j, m) for j in range(m))
        return [even_count(adj1, i) + best2 for i in range(n)]

