var maxTargetNodes = function(edges1, edges2) {
    function colorTree(edges, n) {
        const adj = Array.from({length: n}, () => []);
        for (const [a, b] of edges) { adj[a].push(b); adj[b].push(a); }
        const color = new Array(n).fill(-1);
        color[0] = 0;
        const stack = [0];
        while (stack.length) {
            const u = stack.pop();
            for (const v of adj[u]) {
                if (color[v] === -1) { color[v] = color[u] ^ 1; stack.push(v); }
            }
        }
        return color;
    }
    const n = edges1.length + 1, m = edges2.length + 1;
    const c1 = colorTree(edges1, n);
    const c2 = colorTree(edges2, m);
    const cnt1 = [0, 0], cnt2 = [0, 0];
    for (const c of c1) cnt1[c]++;
    for (const c of c2) cnt2[c]++;
    const best2 = m - Math.min(cnt2[0], cnt2[1]);
    return c1.map(c => (c === 0 ? cnt1[0] : cnt1[1]) + best2);
};
